#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        long long a,b; scanf("%lld %lld",&a,&b);
        long long ans = a*a + b*b*b;
        printf("%lld\n",ans);
    }
    return 0;
}

